sys_security_acl.script:
answer = false;
// Vendor admin can edit everything
if (gs.hasRole('x_1956461_vendor_0.vendor_admin')) {
    answer = true;
}

// Vendor manager can edit only assigned vendor records
else if (
    gs.hasRole('x_1956461_vendor_0.vendor_manager') &&
    current.vendor_manager == gs.getUserID()
) {
    answer = true;
}
